// src/hooks/useVoice.js
import { useState, useCallback, useRef } from 'react';

export function useVoice() {
  const [isListening, setIsListening] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const recognitionRef = useRef(null);

  const speak = useCallback((text, onEnd) => {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    setIsSpeaking(true);

    // Sanitize text for natural speech
    const cleaned = text
      .replace(/₹(\d+)/g, '$1 rupees')           // ₹30 → "30 rupees"
      .replace(/(\d+)\s*km\b/g, '$1 kilometers')  // 2.5km → "2.5 kilometers"
      .replace(/(\d+)\s*m\b/g, '$1 meters')       // 500m → "500 meters"
      .replace(/\bmin\b/g, 'minutes')             // min → minutes (standalone)
      .replace(/\bPF\s*(\d)/g, 'Platform $1')     // PF 2 → Platform 2
      .replace(/\bWR\b/g, 'Western Railway')      // WR abbreviation
      .replace(/[📍🎤🚆🗺️🚉🚌🛺🚕🚶🔊✅⭐📋📡🔍⚠️]/g, ''); // strip emojis from voice

    const utterance = new SpeechSynthesisUtterance(cleaned);
    utterance.lang = 'en-IN';
    utterance.rate = 0.92;
    utterance.pitch = 1.05;

    const loadVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      const preferred =
        voices.find(v => v.lang === 'en-IN') ||
        voices.find(v => v.lang.startsWith('en'));
      if (preferred) utterance.voice = preferred;
    };
    loadVoices();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    utterance.onend = () => { setIsSpeaking(false); if (onEnd) onEnd(); };
    utterance.onerror = () => setIsSpeaking(false);
    window.speechSynthesis.speak(utterance);
  }, []);

  const stopSpeaking = useCallback(() => {
    window.speechSynthesis && window.speechSynthesis.cancel();
    setIsSpeaking(false);
  }, []);

  const startListening = useCallback((onResult, onError) => {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) {
      if (onError) onError('Speech recognition not supported. Please use Google Chrome.');
      return;
    }
    recognitionRef.current = new SR();
    recognitionRef.current.lang = 'en-IN';
    recognitionRef.current.interimResults = false;
    recognitionRef.current.maxAlternatives = 1;

    recognitionRef.current.onstart = () => setIsListening(true);
    recognitionRef.current.onresult = (e) => {
      const text = e.results[0][0].transcript;
      setIsListening(false);
      if (onResult) onResult(text);
    };
    recognitionRef.current.onerror = (e) => {
      setIsListening(false);
      if (onError) onError(e.error);
    };
    recognitionRef.current.onend = () => setIsListening(false);
    recognitionRef.current.start();
  }, []);

  const stopListening = useCallback(() => {
    if (recognitionRef.current) recognitionRef.current.stop();
    setIsListening(false);
  }, []);

  return { speak, stopSpeaking, startListening, stopListening, isListening, isSpeaking };
}
